  1→/**
  2→ * Rehype plugin to transform markdown file links (.md) to page routes
  3→ *
  4→ * Transforms:
  5→ *   ./path/to/file.md → ./path/to/file/
  6→ *   ./path/index.md → ./path/ (index.md becomes directory root)
  7→ *   ../path/file.md#anchor → ../path/file/#anchor
  8→ *   ./file.md?query=param → ./file/?query=param
  9→ *   /docs/absolute/path/file.md → {base}/absolute/path/file/
 10→ *
 11→ * For absolute paths starting with /docs/, the /docs prefix is stripped
 12→ * since the Astro site serves content from the docs directory as the root.
 13→ * The base path is prepended to absolute paths for subdirectory deployments.
 14→ *
 15→ * Affects relative links (./, ../) and absolute paths (/) - external links are unchanged
 16→ */
 17→
 18→import { visit } from 'unist-util-visit';
 19→
 20→/**
 21→ * Convert Markdown file links (.md) into equivalent page route-style links.
 22→ *
 23→ * The returned transformer walks the HTML tree and rewrites anchor `href` values that are relative paths (./, ../) or absolute paths (/) pointing to `.md` files. It preserves query strings and hash anchors, rewrites `.../index.md` to the directory root path (`.../`), and rewrites other `.md` file paths by removing the `.md` extension and ensuring a trailing slash. External links (http://, https://) and non-.md links are left unchanged.
 24→ *
 25→ * @param {Object} options - Plugin options
 26→ * @param {string} options.base - The base path to prepend to absolute URLs (e.g., '/BMAD-METHOD/')
 27→ * @returns {function} A HAST tree transformer that mutates `a` element `href` properties as described.
 28→ */
 29→export default function rehypeMarkdownLinks(options = {}) {
 30→  const base = options.base || '/';
 31→  // Normalize base: ensure it ends with / and doesn't have double slashes
 32→  const normalizedBase = base === '/' ? '' : base.endsWith('/') ? base.slice(0, -1) : base;
 33→
 34→  return (tree) => {
 35→    visit(tree, 'element', (node) => {
 36→      // Only process anchor tags with href
 37→      if (node.tagName !== 'a' || !node.properties?.href) {
 38→        return;
 39→      }
 40→
 41→      const href = node.properties.href;
 42→
 43→      // Skip if not a string (shouldn't happen, but be safe)
 44→      if (typeof href !== 'string') {
 45→        return;
 46→      }
 47→
 48→      // Skip external links (http://, https://, mailto:, etc.)
 49→      if (href.includes('://') || href.startsWith('mailto:') || href.startsWith('tel:')) {
 50→        return;
 51→      }
 52→
 53→      // Only transform paths starting with ./, ../, or / (absolute)
 54→      if (!href.startsWith('./') && !href.startsWith('../') && !href.startsWith('/')) {
 55→        return;
 56→      }
 57→
 58→      // Extract path portion (before ? and #) to check if it's a .md file
 59→      const firstDelimiter = Math.min(
 60→        href.indexOf('?') === -1 ? Infinity : href.indexOf('?'),
 61→        href.indexOf('#') === -1 ? Infinity : href.indexOf('#'),
 62→      );
 63→      const pathPortion = firstDelimiter === Infinity ? href : href.substring(0, firstDelimiter);
 64→
 65→      // Don't transform if path doesn't end with .md
 66→      if (!pathPortion.endsWith('.md')) {
 67→        return;
 68→      }
 69→
 70→      // Split the URL into parts: path, anchor, and query
 71→      let urlPath = pathPortion;
 72→      let anchor = '';
 73→      let query = '';
 74→
 75→      // Extract query string and anchor from original href
 76→      if (firstDelimiter !== Infinity) {
 77→        const suffix = href.substring(firstDelimiter);
 78→        const anchorInSuffix = suffix.indexOf('#');
 79→        if (suffix.startsWith('?')) {
 80→          if (anchorInSuffix !== -1) {
 81→            query = suffix.substring(0, anchorInSuffix);
 82→            anchor = suffix.substring(anchorInSuffix);
 83→          } else {
 84→            query = suffix;
 85→          }
 86→        } else {
 87→          // starts with #
 88→          anchor = suffix;
 89→        }
 90→      }
 91→
 92→      // Track if this was an absolute path (for base path prepending)
 93→      const isAbsolute = urlPath.startsWith('/');
 94→
 95→      // Strip /docs/ prefix from absolute paths (repo-relative → site-relative)
 96→      if (urlPath.startsWith('/docs/')) {
 97→        urlPath = urlPath.slice(5); // Remove '/docs' prefix, keeping the leading /
 98→      }
 99→
100→      // Transform .md to /
101→      // Special case: index.md → directory root (e.g., ./tutorials/index.md → ./tutorials/)
102→      if (urlPath.endsWith('/index.md')) {
103→        urlPath = urlPath.replace(/\/index\.md$/, '/');
104→      } else {
105→        urlPath = urlPath.replace(/\.md$/, '/');
106→      }
107→
108→      // Prepend base path to absolute URLs for subdirectory deployments
109→      if (isAbsolute && normalizedBase) {
110→        urlPath = normalizedBase + urlPath;
111→      }
112→
113→      // Reconstruct the href
114→      node.properties.href = urlPath + query + anchor;
115→    });
116→  };
117→}
