 1→/**
 2→ * Rehype plugin to prepend base path to absolute URLs
 3→ *
 4→ * Transforms:
 5→ *   /img/foo.png → /BMAD-METHOD/img/foo.png (when base is /BMAD-METHOD/)
 6→ *   /downloads/file.zip → /BMAD-METHOD/downloads/file.zip
 7→ *   /llms.txt → /BMAD-METHOD/llms.txt
 8→ *
 9→ * Only affects absolute paths (/) - relative paths and external URLs are unchanged.
10→ * Does NOT process .md links (those are handled by rehype-markdown-links).
11→ */
12→
13→import { visit } from 'unist-util-visit';
14→
15→/**
16→ * Create a rehype plugin that prepends the base path to absolute URLs.
17→ *
18→ * @param {Object} options - Plugin options
19→ * @param {string} options.base - The base path to prepend (e.g., '/BMAD-METHOD/')
20→ * @returns {function} A HAST tree transformer
21→ */
22→export default function rehypeBasePaths(options = {}) {
23→  const base = options.base || '/';
24→
25→  // Normalize base: ensure it ends with / and doesn't have double slashes
26→  const normalizedBase = base === '/' ? '/' : base.endsWith('/') ? base : base + '/';
27→
28→  return (tree) => {
29→    visit(tree, 'element', (node) => {
30→      // Process img tags with src attribute
31→      if (node.tagName === 'img' && node.properties?.src) {
32→        const src = node.properties.src;
33→
34→        if (typeof src === 'string' && src.startsWith('/') && !src.startsWith('//')) {
35→          // Don't transform if already has the base path
36→          if (normalizedBase !== '/' && !src.startsWith(normalizedBase)) {
37→            node.properties.src = normalizedBase + src.slice(1);
38→          }
39→        }
40→      }
41→
42→      // Process iframe tags with src attribute
43→      if (node.tagName === 'iframe' && node.properties?.src) {
44→        const src = node.properties.src;
45→
46→        if (typeof src === 'string' && src.startsWith('/') && !src.startsWith('//')) {
47→          // Don't transform if already has the base path
48→          if (normalizedBase !== '/' && !src.startsWith(normalizedBase)) {
49→            node.properties.src = normalizedBase + src.slice(1);
50→          }
51→        }
52→      }
53→
54→      // Process anchor tags with href attribute
55→      if (node.tagName === 'a' && node.properties?.href) {
56→        const href = node.properties.href;
57→
58→        if (typeof href !== 'string') {
59→          return;
60→        }
61→
62→        // Only transform absolute paths starting with / (but not //)
63→        if (!href.startsWith('/') || href.startsWith('//')) {
64→          return;
65→        }
66→
67→        // Skip if already has the base path
68→        if (normalizedBase !== '/' && href.startsWith(normalizedBase)) {
69→          return;
70→        }
71→
72→        // Skip .md links - those are handled by rehype-markdown-links
73→        // Extract path portion (before ? and #)
74→        const firstDelimiter = Math.min(
75→          href.indexOf('?') === -1 ? Infinity : href.indexOf('?'),
76→          href.indexOf('#') === -1 ? Infinity : href.indexOf('#'),
77→        );
78→        const pathPortion = firstDelimiter === Infinity ? href : href.substring(0, firstDelimiter);
79→
80→        if (pathPortion.endsWith('.md')) {
81→          return; // Let rehype-markdown-links handle this
82→        }
83→
84→        // Prepend base path
85→        node.properties.href = normalizedBase + href.slice(1);
86→      }
87→    });
88→  };
89→}
