  1→/**
  2→ * BMAD Method Documentation - Custom Styles for Starlight
  3→ * Electric Blue theme optimized for dark mode
  4→ *
  5→ * CSS Variable Mapping:
  6→ * Docusaurus → Starlight
  7→ * --ifm-color-primary → --sl-color-accent
  8→ * --ifm-background-color → --sl-color-bg
  9→ * --ifm-font-color-base → --sl-color-text
 10→ */
 11→
 12→/* ============================================
 13→   COLOR PALETTE - Light Mode
 14→   ============================================ */
 15→:root {
 16→  --ai-banner-height: 2.75rem;
 17→  --sl-nav-height: 6.25rem; /* Base nav height (~3.5rem) + banner height (2.75rem) */
 18→
 19→  /* Full-width content - override Starlight's default 45rem/67.5rem */
 20→  --sl-content-width: 100%;
 21→
 22→  /* Primary accent colors - purple to match Docusaurus */
 23→  --sl-color-accent-low: #e0e0ff;
 24→  --sl-color-accent: #8c8cff;
 25→  --sl-color-accent-high: #4141ff;
 26→
 27→  /* Text colors */
 28→  --sl-color-white: #1e293b;
 29→  --sl-color-gray-1: #334155;
 30→  --sl-color-gray-2: #475569;
 31→  --sl-color-gray-3: #64748b;
 32→  --sl-color-gray-4: #94a3b8;
 33→  --sl-color-gray-5: #cbd5e1;
 34→  --sl-color-gray-6: #e2e8f0;
 35→  --sl-color-black: #f8fafc;
 36→
 37→  /* Font settings */
 38→  --sl-font: system-ui, -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, 'Helvetica Neue', Arial, sans-serif;
 39→  --sl-text-base: 1rem;
 40→  --sl-line-height: 1.7;
 41→
 42→  /* Code highlighting */
 43→  --sl-color-bg-inline-code: rgba(140, 140, 255, 0.1);
 44→}
 45→
 46→/* ============================================
 47→   COLOR PALETTE - Dark Mode (Primary Focus)
 48→   ============================================ */
 49→:root[data-theme='dark'] {
 50→  /* Full-width content - override Starlight's default */
 51→  --sl-content-width: 100%;
 52→
 53→  /* Primary accent colors - purple to match Docusaurus */
 54→  --sl-color-accent-low: #2a2a5a;
 55→  --sl-color-accent: #8c8cff;
 56→  --sl-color-accent-high: #b9b9ff;
 57→
 58→  /* Background colors */
 59→  --sl-color-bg: #1b1b1d;
 60→  --sl-color-bg-nav: #1b1b1d;
 61→  --sl-color-bg-sidebar: #1b1b1d;
 62→  --sl-color-hairline-light: rgba(140, 140, 255, 0.1);
 63→  --sl-color-hairline: rgba(140, 140, 255, 0.15);
 64→
 65→  /* Text colors */
 66→  --sl-color-white: #f8fafc;
 67→  --sl-color-gray-1: #e2e8f0;
 68→  --sl-color-gray-2: #cbd5e1;
 69→  --sl-color-gray-3: #94a3b8;
 70→  --sl-color-gray-4: #64748b;
 71→  --sl-color-gray-5: #475569;
 72→  --sl-color-gray-6: #334155;
 73→  --sl-color-black: #1b1b1d;
 74→
 75→  /* Code highlighting */
 76→  --sl-color-bg-inline-code: rgba(140, 140, 255, 0.15);
 77→}
