 79→/* ============================================
 80→   TYPOGRAPHY
 81→   ============================================ */
 82→.sl-markdown-content h1 {
 83→  margin-bottom: 1.5rem;
 84→}
 85→
 86→.sl-markdown-content h2 {
 87→  margin-top: 2.5rem;
 88→  margin-bottom: 1rem;
 89→}
 90→
 91→.sl-markdown-content h3 {
 92→  margin-top: 2rem;
 93→  margin-bottom: 0.75rem;
 94→}
 95→
 96→.sl-markdown-content p {
 97→  margin-bottom: 1.25rem;
 98→}
 99→
100→/* ============================================
101→   SIDEBAR & NAVIGATION
102→   Clean styling inspired by React Native docs
103→   ============================================ */
104→
105→/* Base transition for all sidebar links */
106→.sidebar-content a {
107→  transition:
108→    background-color 0.15s ease,
109→    color 0.15s ease,
110→    border-color 0.15s ease;
111→  border-radius: 4px;
112→}
113→
114→/* Top-level sidebar items (Diataxis categories) */
115→.sidebar-content > ul > li > details > summary,
116→.sidebar-content > ul > li > a {
117→  font-weight: 700;
118→  font-size: 0.9375rem;
119→  padding: 0.5rem 0.75rem;
120→}
121→
122→/* Nested sidebar items */
123→.sidebar-content ul ul a {
124→  font-weight: 500;
125→  font-size: 0.875rem;
126→  padding: 0.375rem 0.75rem;
127→  padding-left: 1.5rem;
128→  border-left: 3px solid transparent;
129→}
130→
131→/* Deep nested items */
132→.sidebar-content ul ul ul a {
133→  font-weight: 400;
134→  font-size: 0.8125rem;
135→  padding-left: 2.25rem;
136→}
137→
138→/* Active state - thin left accent bar */
139→.sidebar-content a[aria-current='page'] {
140→  background-color: rgba(140, 140, 255, 0.08);
141→  color: var(--sl-color-accent);
142→  border-left-color: var(--sl-color-accent);
143→  font-weight: 600;
144→}
145→
146→:root[data-theme='dark'] .sidebar-content a[aria-current='page'] {
147→  background-color: rgba(140, 140, 255, 0.1);
148→  color: var(--sl-color-accent-high);
149→  border-left-color: var(--sl-color-accent);
150→}
151→
152→/* Hover states */
153→.sidebar-content a:hover {
154→  background-color: rgba(0, 0, 0, 0.05);
155→}
156→
157→:root[data-theme='dark'] .sidebar-content a:hover {
158→  background-color: rgba(255, 255, 255, 0.05);
159→}
160→
161→/* Section spacing */
162→.sidebar-content > ul > li {
163→  margin-top: 0.75rem;
164→}
165→
166→.sidebar-content > ul > li:first-child {
167→  margin-top: 0;
168→}
169→
170→/* Lighter chevrons/carets */
171→.sidebar-content summary::marker,
172→.sidebar-content details > summary::after {
173→  opacity: 0.4;
174→}
175→
176→.sidebar-content summary:hover::marker,
177→.sidebar-content details > summary:hover::after {
178→  opacity: 0.6;
179→}
