300→.sl-link-card {
301→  border-radius: 12px;
302→  border: 2px solid var(--sl-color-gray-5);
303→  transition:
304→    transform 0.2s ease,
305→    box-shadow 0.2s ease,
306→    border-color 0.2s ease;
307→}
308→
309→.sl-link-card:hover {
310→  transform: translateY(-3px);
311→  border-color: var(--sl-color-accent);
312→}
313→
314→:root[data-theme='dark'] .sl-link-card {
315→  border-color: rgba(140, 140, 255, 0.2);
316→}
317→
318→:root[data-theme='dark'] .sl-link-card:hover {
319→  border-color: rgba(140, 140, 255, 0.5);
320→}
321→
322→/* ============================================
323→   BUTTONS
324→   ============================================ */
