326→button {
327→  transition:
328→    background-color 0.2s ease,
329→    transform 0.1s ease;
330→}
331→
332→.sl-flex a[href]:hover,
333→button:hover {
334→  transform: translateY(-1px);
335→}
336→
337→/* ============================================
338→   MISC ENHANCEMENTS
339→   ============================================ */
340→
341→/* Smooth scrolling */
342→html {
343→  scroll-behavior: smooth;
344→}
345→
346→/* Better link underlines */
347→.sl-markdown-content a:not(.sl-link-card) {
348→  text-decoration-thickness: 1px;
349→  text-underline-offset: 2px;
350→}
351→
352→/* Table styling */
353→table {
354→  display: table;
355→  width: 100%;
356→}
357→
358→:root[data-theme='dark'] table {
359→  border-color: rgba(140, 140, 255, 0.1);
360→}
361→
362→:root[data-theme='dark'] table th {
363→  background-color: rgba(140, 140, 255, 0.05);
364→}
365→
366→:root[data-theme='dark'] table tr:nth-child(2n) {
367→  background-color: rgba(140, 140, 255, 0.02);
368→}
369→
370→/* Blockquotes */
371→blockquote {
372→  border-left-color: var(--sl-color-accent);
373→  background-color: rgba(140, 140, 255, 0.05);
374→  border-radius: 0 8px 8px 0;
