376→}
377→
378→/* ============================================
379→   ADMONITIONS (Starlight Asides)
380→   Rounded, no left border bar
381→   ============================================ */
382→.starlight-aside {
383→  margin-bottom: 1.5rem;
384→  padding: 1.25rem 1.5rem;
385→  border-radius: 12px;
386→  border: none;
387→  border-left: 0;
388→  box-shadow: 0 1px 4px rgba(0, 0, 0, 0.08);
389→}
390→
391→/* Tip aside */
