393→  background-color: rgba(16, 185, 129, 0.08);
394→}
395→
396→.starlight-aside--tip .starlight-aside__title {
397→  color: #059669;
398→}
399→
400→:root[data-theme='dark'] .starlight-aside--tip {
401→  background-color: rgba(16, 185, 129, 0.12);
402→}
403→
404→:root[data-theme='dark'] .starlight-aside--tip .starlight-aside__title {
405→  color: #34d399;
406→}
