184→/**
185→ * Builds a consolidated llms-full.txt containing all Markdown files under docsDir wrapped in <document path="..."> tags for LLM consumption.
186→ *
187→ * Writes the generated file to outputDir/llms-full.txt. Files matching LLM_EXCLUDE_PATTERNS are skipped; read errors for individual files are logged. The combined content is validated against configured size thresholds (will exit on overflow and warn if near limit).
188→ * @param {string} docsDir - Root directory containing source Markdown files; paths in the output are relative to this directory.
189→ * @param {string} outputDir - Directory where llms-full.txt will be written.
190→ */
191→function generateLlmsFullTxt(docsDir, outputDir) {
192→  console.log('  → Generating llms-full.txt...');
193→
194→  const date = new Date().toISOString().split('T')[0];
195→  const files = getAllMarkdownFiles(docsDir);
196→
197→  const output = [
198→    '# Test Architect (TEA) Documentation (Full)',
199→    '',
200→    '> Complete documentation for AI consumption',
201→    `> Generated: ${date}`,
202→    `> Repository: ${REPO_URL}`,
203→    '',
204→  ];
205→
206→  let fileCount = 0;
207→  let skippedCount = 0;
208→
209→  for (const mdPath of files) {
210→    if (shouldExcludeFromLlm(mdPath)) {
211→      skippedCount++;
212→      continue;
213→    }
214→
215→    const fullPath = path.join(docsDir, mdPath);
216→    try {
217→      const content = readMarkdownContent(fullPath);
218→      output.push(`<document path="${mdPath}">`, content, '</document>', '');
219→      fileCount++;
220→    } catch (error) {
221→      console.error(`    Warning: Could not read ${mdPath}: ${error.message}`);
222→    }
223→  }
224→
225→  const result = output.join('\n');
226→  validateLlmSize(result);
227→
228→  const outputPath = path.join(outputDir, 'llms-full.txt');
229→  fs.writeFileSync(outputPath, result, 'utf-8');
230→
231→  const tokenEstimate = Math.floor(result.length / 4).toLocaleString();
232→  console.log(
233→    `    Processed ${fileCount} files (skipped ${skippedCount}), ${result.length.toLocaleString()} chars (~${tokenEstimate} tokens)`,
234→  );
235→}
