  1→/**
  2→ * Documentation Link Validator
  3→ *
  4→ * Validates site-relative links in markdown files and attempts to fix broken ones.
  5→ *
  6→ * What it checks:
  7→ * - All site-relative links (starting with /) point to existing .md files
  8→ * - Anchor links (#section) point to valid headings
  9→ *
 10→ * What it fixes:
 11→ * - Broken links where the target file can be found elsewhere in /docs
 12→ *
 13→ * Usage:
 14→ *   node tools/validate-doc-links.js           # Dry run (validate and show issues)
 15→ *   node tools/validate-doc-links.js --write   # Fix auto-fixable issues
 16→ */
 17→
 18→const fs = require('node:fs');
 19→const path = require('node:path');
 20→
 21→const DOCS_ROOT = path.resolve(__dirname, '../docs');
 22→const DRY_RUN = !process.argv.includes('--write');
 23→
 24→// Regex to match markdown links with site-relative paths
 25→const LINK_REGEX = /\[([^\]]*)\]\((\/[^)]+)\)/g;
 26→
 27→// File extensions that are static assets, not markdown docs
 28→const STATIC_ASSET_EXTENSIONS = ['.zip', '.txt', '.pdf', '.png', '.jpg', '.jpeg', '.gif', '.svg', '.webp', '.ico'];
 29→
 30→// Custom Astro page routes (not part of the docs content collection)
 31→const CUSTOM_PAGE_ROUTES = new Set([]);
 32→
 33→// Regex to extract headings for anchor validation
 34→const HEADING_PATTERN = /^#{1,6}\s+(.+)$/gm;
 35→
 36→/**
 37→ * Get all markdown files in docs directory, excluding _* directories/files
 38→ */
 39→function getMarkdownFiles(dir) {
 40→  const files = [];
 41→
 42→  function walk(currentDir) {
 43→    const entries = fs.readdirSync(currentDir, { withFileTypes: true });
 44→
 45→    for (const entry of entries) {
 46→      const fullPath = path.join(currentDir, entry.name);
 47→
 48→      if (entry.name.startsWith('_')) {
 49→        continue;
 50→      }
 51→
 52→      if (entry.isDirectory()) {
 53→        walk(fullPath);
 54→      } else if (entry.isFile() && entry.name.endsWith('.md')) {
 55→        files.push(fullPath);
 56→      }
 57→    }
 58→  }
 59→
 60→  walk(dir);
 61→  return files;
 62→}
 63→
 64→/**
 65→ * Strip fenced code blocks from content
 66→ */
 67→function stripCodeBlocks(content) {
 68→  return content.replaceAll(/```[\s\S]*?```/g, '');
 69→}
 70→
 71→/**
 72→ * Convert a heading to its anchor slug
 73→ */
 74→function headingToAnchor(heading) {
 75→  return heading
 76→    .toLowerCase()
 77→    .replaceAll(/[\u{1F300}-\u{1F9FF}]/gu, '') // Remove emojis
 78→    .replaceAll(/[^\w\s-]/g, '') // Remove special chars
 79→    .replaceAll(/\s+/g, '-') // Spaces to hyphens
 80→    .replaceAll(/-+/g, '-') // Collapse hyphens
 81→    .replaceAll(/^-+|-+$/g, ''); // Trim hyphens
 82→}
 83→
 84→/**
 85→ * Extract anchor slugs from a markdown file
 86→ */
 87→function extractAnchors(content) {
 88→  const anchors = new Set();
 89→  let match;
 90→
 91→  HEADING_PATTERN.lastIndex = 0;
 92→  while ((match = HEADING_PATTERN.exec(content)) !== null) {
 93→    const headingText = match[1]
 94→      .trim()
 95→      .replaceAll(/`([^`]+)`/g, '$1')
 96→      .replaceAll(/\*\*([^*]+)\*\*/g, '$1')
 97→      .replaceAll(/\*([^*]+)\*/g, '$1')
 98→      .replaceAll(/\[([^\]]+)\]\([^)]+\)/g, '$1')
 99→      .trim();
100→    anchors.add(headingToAnchor(headingText));
101→  }
102→
103→  return anchors;
104→}
105→
106→/**
107→ * Resolve a site-relative link to a file path
108→ * /docs/how-to/installation/install-bmad.md -> docs/how-to/installation/install-bmad.md
109→ * /how-to/installation/install-bmad/ -> docs/how-to/installation/install-bmad.md or .../index.md
110→ */
111→function resolveLink(siteRelativePath) {
112→  // Strip anchor and query
113→  let checkPath = siteRelativePath.split('#')[0].split('?')[0];
114→
115→  // Strip /docs/ prefix if present (repo-relative links)
116→  if (checkPath.startsWith('/docs/')) {
117→    checkPath = checkPath.slice(5); // Remove '/docs' but keep leading '/'
118→  }
119→
120→  if (checkPath.endsWith('/')) {
121→    // Could be file.md or directory/index.md
122→    const asFile = path.join(DOCS_ROOT, checkPath.slice(0, -1) + '.md');
123→    const asIndex = path.join(DOCS_ROOT, checkPath, 'index.md');
124→
125→    if (fs.existsSync(asFile)) return asFile;
126→    if (fs.existsSync(asIndex)) return asIndex;
127→    return null;
128→  }
129→
130→  // Direct path (e.g., /path/file.md)
131→  const direct = path.join(DOCS_ROOT, checkPath);
132→  if (fs.existsSync(direct)) return direct;
133→
134→  // Try with .md extension
135→  const withMd = direct + '.md';
136→  if (fs.existsSync(withMd)) return withMd;
137→
138→  return null;
139→}
140→
141→/**
142→ * Search for a file with directory context
143→ */
144→function findFileWithContext(brokenPath) {
145→  // Extract filename and parent directory from the broken path
146→  // e.g., /tutorials/getting-started/foo/ -> parent: getting-started, file: foo.md
147→  const cleanPath = brokenPath.replace(/\/$/, '').replace(/^\//, '');
148→  const parts = cleanPath.split('/');
149→  const fileName = parts.at(-1) + '.md';
150→  const parentDir = parts.length > 1 ? parts.at(-2) : null;
151→
152→  const allFiles = getMarkdownFiles(DOCS_ROOT);
153→  const matches = [];
154→
155→  for (const file of allFiles) {
156→    const fileBaseName = path.basename(file);
157→    const fileParentDir = path.basename(path.dirname(file));
158→
159→    // Exact filename match with parent directory context
160→    if (fileBaseName === fileName) {
161→      if (parentDir && fileParentDir === parentDir) {
162→        // Strong match: both filename and parent dir match
163→        return [file];
164→      }
165→      matches.push(file);
166→    }
167→
168→    // Also check for index.md in a matching directory
169→    if (fileBaseName === 'index.md' && fileParentDir === fileName.replace('.md', '')) {
170→      matches.push(file);
171→    }
172→  }
173→
174→  return matches;
175→}
176→
177→/**
178→ * Convert absolute file path to site-relative URL
179→ */
180→function fileToSiteRelative(filePath) {
181→  let relative = '/' + path.relative(DOCS_ROOT, filePath);
182→  relative = relative.split(path.sep).join('/');
183→
184→  if (relative.endsWith('/index.md')) {
185→    return relative.replace(/\/index\.md$/, '/');
186→  }
187→  return relative.replace(/\.md$/, '/');
188→}
189→
190→/**
191→ * Process a single file and find issues
192→ */
193→function processFile(filePath) {
194→  const content = fs.readFileSync(filePath, 'utf-8');
195→  const strippedContent = stripCodeBlocks(content);
196→  const issues = [];
197→
198→  let match;
199→  LINK_REGEX.lastIndex = 0;
200→
201→  while ((match = LINK_REGEX.exec(strippedContent)) !== null) {
202→    const linkText = match[1];
203→    const href = match[2];
204→
205→    // Extract path and anchor
206→    const hashIndex = href.indexOf('#');
207→    const linkPath = hashIndex === -1 ? href : href.slice(0, hashIndex);
208→    const anchor = hashIndex === -1 ? null : href.slice(hashIndex + 1);
209→
210→    // Skip static asset links (zip, txt, images, etc.)
211→    const linkLower = linkPath.toLowerCase();
212→    if (STATIC_ASSET_EXTENSIONS.some((ext) => linkLower.endsWith(ext))) {
213→      continue;
214→    }
215→
216→    // Skip custom Astro page routes
217→    if (CUSTOM_PAGE_ROUTES.has(linkPath)) {
218→      continue;
219→    }
220→
221→    // Validate the link target exists
222→    const targetFile = resolveLink(linkPath);
223→
224→    if (!targetFile) {
225→      // Link is broken - try to find the file
226→      const candidates = findFileWithContext(linkPath);
227→
228→      const issue = {
229→        type: 'broken-link',
230→        linkText,
231→        href,
232→        linkPath,
233→        fullMatch: match[0],
234→      };
235→
236→      if (candidates.length === 1) {
237→        issue.status = 'auto-fixable';
238→        issue.suggestedFix = fileToSiteRelative(candidates[0]) + (anchor ? '#' + anchor : '');
239→        issue.foundAt = path.relative(DOCS_ROOT, candidates[0]);
240→      } else if (candidates.length > 1) {
241→        issue.status = 'needs-review';
242→        issue.candidates = candidates.map((c) => path.relative(DOCS_ROOT, c));
243→      } else {
244→        issue.status = 'manual-check';
245→      }
246→
247→      issues.push(issue);
248→      continue;
249→    }
250→
251→    // Validate anchor if present
252→    if (anchor) {
253→      const targetContent = fs.readFileSync(targetFile, 'utf-8');
254→      const anchors = extractAnchors(targetContent);
255→
256→      if (!anchors.has(anchor)) {
257→        issues.push({
258→          type: 'broken-anchor',
259→          linkText,
260→          href,
261→          anchor,
262→          status: 'manual-check',
263→          message: `Anchor "#${anchor}" not found`,
264→        });
265→      }
266→    }
267→  }
268→
269→  return { content, issues };
270→}
271→
272→/**
273→ * Apply fixes to file content
274→ */
275→function applyFixes(content, issues) {
276→  let updated = content;
277→
278→  for (const issue of issues) {
279→    if (issue.status === 'auto-fixable' && issue.suggestedFix) {
280→      const oldLink = `[${issue.linkText}](${issue.href})`;
281→      const newLink = `[${issue.linkText}](${issue.suggestedFix})`;
282→      updated = updated.replaceAll(oldLink, newLink);
283→    }
284→  }
285→
286→  return updated;
287→}
288→
289→// Main execution
290→console.log(`\nValidating docs in: ${DOCS_ROOT}`);
291→console.log(`Mode: ${DRY_RUN ? 'DRY RUN (use --write to fix)' : 'WRITE MODE'}\n`);
292→
293→const files = getMarkdownFiles(DOCS_ROOT);
294→console.log(`Found ${files.length} markdown files\n`);
295→
296→let totalIssues = 0;
297→let autoFixable = 0;
298→let needsReview = 0;
299→let manualCheck = 0;
300→let filesWithIssues = 0;
301→
302→const allIssues = [];
303→
304→for (const filePath of files) {
305→  const relativePath = path.relative(DOCS_ROOT, filePath);
306→  const { content, issues } = processFile(filePath);
307→
308→  if (issues.length > 0) {
309→    filesWithIssues++;
310→    totalIssues += issues.length;
311→
312→    console.log(`\n${relativePath}`);
313→
314→    for (const issue of issues) {
315→      if (issue.status === 'auto-fixable') {
316→        autoFixable++;
317→        console.log(`  [FIX] ${issue.href}`);
318→        console.log(`     -> ${issue.suggestedFix}`);
319→      } else if (issue.status === 'needs-review') {
320→        needsReview++;
321→        console.log(`  [REVIEW] ${issue.href}`);
322→        console.log(`     Multiple matches found:`);
323→        for (const candidate of issue.candidates) {
324→          console.log(`       - ${candidate}`);
325→        }
326→      } else if (issue.type === 'broken-anchor') {
327→        manualCheck++;
328→        console.log(`  [MANUAL] ${issue.href}`);
329→        console.log(`     ${issue.message}`);
330→      } else {
331→        manualCheck++;
332→        console.log(`  [MANUAL] ${issue.href}`);
333→        console.log(`     File not found anywhere - may need to remove link`);
334→      }
335→
336→      allIssues.push({ file: relativePath, ...issue });
337→    }
338→
339→    // Apply fixes if not dry run
340→    if (!DRY_RUN) {
341→      const fixableIssues = issues.filter((i) => i.status === 'auto-fixable');
342→      if (fixableIssues.length > 0) {
343→        const updated = applyFixes(content, fixableIssues);
344→        fs.writeFileSync(filePath, updated, 'utf-8');
345→      }
346→    }
347→  }
348→}
349→
350→console.log(`\n${'─'.repeat(60)}`);
351→console.log(`\nSummary:`);
