  1→/**
  2→ * Fix Documentation Links
  3→ *
  4→ * Converts relative markdown links to repo-relative paths with .md extension.
  5→ * This ensures links work both in GitHub and on the Astro/Starlight site
  6→ * (the rehype plugin transforms /docs/path/file.md → /path/file/ at build time).
  7→ *
  8→ * - ./file.md → /docs/current/path/file.md
  9→ * - ../other/file.md → /docs/resolved/path/file.md
 10→ * - /path/file/ → /docs/path/file.md (or /docs/path/file/index.md if it's a directory)
 11→ *
 12→ * Usage:
 13→ *   node tools/fix-doc-links.js           # Dry run (shows what would change)
 14→ *   node tools/fix-doc-links.js --write   # Actually write changes
 15→ */
 16→
 17→const fs = require('node:fs');
 18→const path = require('node:path');
 19→
 20→const DOCS_ROOT = path.resolve(__dirname, '../docs');
 21→const DRY_RUN = !process.argv.includes('--write');
 22→
 23→// Regex to match markdown links:
 24→// - [text](path.md) or [text](path.md#anchor) - existing .md links
 25→// - [text](/path/to/page/) or [text](/path/to/page/#anchor) - site-relative links to convert
 26→const MARKDOWN_LINK_REGEX = /\[([^\]]*)\]\(([^)]+(?:\.md|\/))(?:#[^)]*)?(?:\?[^)]*)?\)/g;
 27→// Simpler approach: match all markdown links and filter in the handler
 28→const ALL_MARKDOWN_LINKS_REGEX = /\[([^\]]*)\]\(([^)]+)\)/g;
 29→
 30→/**
 31→ * Get all markdown files in docs directory, excluding _* directories/files
 32→ */
 33→function getMarkdownFiles(dir) {
 34→  const files = [];
 35→
 36→  function walk(currentDir) {
 37→    const entries = fs.readdirSync(currentDir, { withFileTypes: true });
 38→
 39→    for (const entry of entries) {
 40→      const fullPath = path.join(currentDir, entry.name);
 41→
 42→      // Skip underscore-prefixed entries
 43→      if (entry.name.startsWith('_')) {
 44→        continue;
 45→      }
 46→
 47→      if (entry.isDirectory()) {
 48→        walk(fullPath);
 49→      } else if (entry.isFile() && entry.name.endsWith('.md')) {
 50→        files.push(fullPath);
 51→      }
 52→    }
 53→  }
 54→
 55→  walk(dir);
 56→  return files;
 57→}
 58→
 59→/**
 60→ * Convert a markdown link href to repo-relative path with .md extension
 61→ *
 62→ * @param {string} href - The original href (e.g., "./file.md", "/path/to/page/", "/path/to/page/#anchor")
 63→ * @param {string} currentFilePath - Absolute path to the file containing this link
 64→ * @returns {string|null} - Repo-relative path (e.g., "/docs/path/to/file.md"), or null if shouldn't be converted
 65→ */
 66→function convertToRepoRelative(href, currentFilePath) {
 67→  // Skip external links
 68→  if (href.includes('://') || href.startsWith('mailto:') || href.startsWith('tel:')) {
 69→    return null;
 70→  }
 71→
 72→  // Skip anchor-only links
 73→  if (href.startsWith('#')) {
 74→    return null;
 75→  }
 76→
 77→  // Extract anchor and query string if present
 78→  let anchor = '';
 79→  let query = '';
 80→  let pathPortion = href;
 81→
 82→  const hashIndex = href.indexOf('#');
 83→  const queryIndex = href.indexOf('?');
 84→
 85→  if (hashIndex !== -1 || queryIndex !== -1) {
 86→    const firstDelimiter = Math.min(hashIndex === -1 ? Infinity : hashIndex, queryIndex === -1 ? Infinity : queryIndex);
 87→    pathPortion = href.slice(0, Math.max(0, firstDelimiter));
 88→
 89→    const suffix = href.slice(Math.max(0, firstDelimiter));
 90→    const anchorInSuffix = suffix.indexOf('#');
 91→
 92→    if (suffix.startsWith('?')) {
 93→      if (anchorInSuffix === -1) {
 94→        query = suffix;
 95→      } else {
 96→        query = suffix.slice(0, Math.max(0, anchorInSuffix));
 97→        anchor = suffix.slice(Math.max(0, anchorInSuffix));
 98→      }
 99→    } else {
100→      anchor = suffix;
101→    }
102→  }
103→
104→  // Skip non-documentation links (images, external assets, etc.)
105→  const ext = path.extname(pathPortion).toLowerCase();
106→  if (
107→    ext &&
108→    ext !== '.md' &&
109→    !['.md'].includes(ext) && // Has an extension that's not .md - skip unless it's a trailing slash path
110→    !pathPortion.endsWith('/')
111→  ) {
112→    return null;
113→  }
114→
115→  // Check if original path ends with / (directory reference) BEFORE path.join normalizes it
116→  const isDirectoryPath = pathPortion.endsWith('/');
117→
118→  let absolutePath;
119→
120→  if (pathPortion.startsWith('/docs/')) {
121→    // Already repo-relative with /docs/ prefix
122→    absolutePath = path.join(path.dirname(DOCS_ROOT), pathPortion);
123→  } else if (pathPortion.startsWith('/')) {
124→    // Site-relative (e.g., /tutorials/getting-started/) - resolve from docs root
125→    absolutePath = path.join(DOCS_ROOT, pathPortion);
126→  } else {
127→    // Relative path (./, ../, or bare filename) - resolve from current file's directory
128→    const currentDir = path.dirname(currentFilePath);
129→    absolutePath = path.resolve(currentDir, pathPortion);
130→  }
131→
132→  // Convert to repo-relative path (with /docs/ prefix)
133→  let repoRelative = '/docs/' + path.relative(DOCS_ROOT, absolutePath);
134→
135→  // Normalize path separators for Windows
136→  repoRelative = repoRelative.split(path.sep).join('/');
137→
138→  // If original path was a directory reference (ended with /), check for index.md or file.md
139→  if (isDirectoryPath) {
140→    const relativeDir = repoRelative.slice(6); // Remove '/docs/'
141→
142→    // Handle root path case (relativeDir is empty or just '.')
143→    const normalizedDir = relativeDir === '' || relativeDir === '.' ? '' : relativeDir;
144→    const indexPath = path.join(DOCS_ROOT, normalizedDir, 'index.md');
145→    const filePath = normalizedDir ? path.join(DOCS_ROOT, normalizedDir + '.md') : null;
146→
147→    if (fs.existsSync(indexPath)) {
148→      // Avoid double slash when repoRelative is '/docs/' (root case)
149→      repoRelative = repoRelative.endsWith('/') ? repoRelative + 'index.md' : repoRelative + '/index.md';
150→    } else if (filePath && fs.existsSync(filePath)) {
151→      repoRelative = repoRelative + '.md';
152→    } else {
153→      // Neither exists - default to index.md and let validation catch it
154→      repoRelative = repoRelative.endsWith('/') ? repoRelative + 'index.md' : repoRelative + '/index.md';
155→    }
156→  } else if (!repoRelative.endsWith('.md')) {
157→    // Path doesn't end with .md - add .md
158→    repoRelative = repoRelative + '.md';
159→  }
160→
161→  return repoRelative + query + anchor;
162→}
163→
164→/**
165→ * Process a single markdown file, skipping links inside fenced code blocks
166→ *
167→ * @param {string} filePath - Absolute path to the file
168→ * @returns {Object} - { changed: boolean, original: string, updated: string, changes: Array }
169→ */
170→function processFile(filePath) {
171→  const original = fs.readFileSync(filePath, 'utf-8');
172→  const changes = [];
173→
174→  // Extract fenced code blocks and replace with placeholders
175→  const codeBlocks = [];
176→  const CODE_PLACEHOLDER = '\u0000CODE_BLOCK_';
177→
178→  let contentWithPlaceholders = original.replaceAll(/```[\s\S]*?```/g, (match) => {
179→    const index = codeBlocks.length;
180→    codeBlocks.push(match);
181→    return `${CODE_PLACEHOLDER}${index}\u0000`;
182→  });
183→
184→  // Process links only in non-code-block content
185→  contentWithPlaceholders = contentWithPlaceholders.replaceAll(ALL_MARKDOWN_LINKS_REGEX, (match, linkText, href) => {
186→    const newHref = convertToRepoRelative(href, filePath);
187→
188→    // Skip if conversion returned null (external link, anchor, etc.)
189→    if (newHref === null) {
190→      return match;
191→    }
192→
193→    // Only record as change if actually different
194→    if (newHref !== href) {
195→      changes.push({ from: href, to: newHref });
196→      return `[${linkText}](${newHref})`;
197→    }
198→
199→    return match;
200→  });
201→
202→  // Restore code blocks
203→  const updated = contentWithPlaceholders.replaceAll(
204→    new RegExp(`${CODE_PLACEHOLDER}(\\d+)\u0000`, 'g'),
205→    (match, index) => codeBlocks[parseInt(index, 10)],
206→  );
