 1→/**
 2→ * Resolve the site's base URL using cascading environment defaults.
 3→ *
 4→ * Preference order: use SITE_URL if set; otherwise derive a GitHub Pages URL from GITHUB_REPOSITORY; otherwise use the local development URL.
 5→ * @returns {string} The resolved site URL (SITE_URL override, or `https://{owner}.github.io/{repo}`, or `http://localhost:3000`).
 6→ */
 7→export function getSiteUrl() {
 8→  // Explicit override (works in both local and GitHub Actions)
 9→  if (process.env.SITE_URL) {
10→    return process.env.SITE_URL;
11→  }
12→
13→  // GitHub Actions: compute from repository context
14→  if (process.env.GITHUB_REPOSITORY) {
15→    const parts = process.env.GITHUB_REPOSITORY.split('/');
16→    if (parts.length !== 2 || !parts[0] || !parts[1]) {
17→      throw new Error(`Invalid GITHUB_REPOSITORY format: "${process.env.GITHUB_REPOSITORY}". Expected "owner/repo".`);
18→    }
19→    const [owner, repo] = parts;
20→    return `https://${owner}.github.io/${repo}`;
21→  }
22→
23→  // Local development: use dev server
24→  return 'http://localhost:3000';
25→}
