  1→/**
  2→ * TEA (Test Engineering Architect) Documentation Build Pipeline
  3→ *
  4→ * Consolidates docs from multiple sources, generates LLM-friendly files,
  5→ * creates downloadable bundles, and builds the Astro+Starlight site.
  6→ *
  7→ * Build outputs:
  8→ *   build/artifacts/     - With llms.txt, llms-full.txt, ZIPs
  9→ *   build/site/          - Final Astro output (deployable)
 10→ */
 11→
 12→const { execSync } = require('node:child_process');
 13→const fs = require('node:fs');
 14→const path = require('node:path');
 15→const archiver = require('archiver');
 16→
 17→// =============================================================================
 18→// Configuration
 19→// =============================================================================
 20→
 21→const PROJECT_ROOT = path.dirname(__dirname);
 22→const BUILD_DIR = path.join(PROJECT_ROOT, 'build');
 23→
 24→const SITE_URL = process.env.SITE_URL || 'https://test-architect.bmad-method.org';
 25→const REPO_URL = 'https://github.com/bmad-code-org/bmad-method-test-architecture-enterprise';
 26→
 27→// DO NOT CHANGE THESE VALUES!
 28→// llms-full.txt is consumed by AI agents as context. Most LLMs have ~200k token limits.
 29→// 600k chars ≈ 150k tokens (safe margin). Exceeding this breaks AI agent functionality.
 30→const LLM_MAX_CHARS = 600_000;
 31→const LLM_WARN_CHARS = 500_000;
 32→
 33→const LLM_EXCLUDE_PATTERNS = [
 34→  'changelog',
 35→  'downloads/',
 36→  'reference/glossary/',
 37→  // Note: Files/dirs starting with _ (like _STYLE_GUIDE.md, _archive/) are excluded in shouldExcludeFromLlm()
 38→];
 39→
 40→// =============================================================================
 41→// Main Entry Point
 42→/**
 43→ * Orchestrates the full BMAD documentation build pipeline.
 44→ *
 45→ * Executes the high-level build steps in sequence: prints headers and paths, validates internal
 46→ * documentation links, cleans the build directory, generates artifacts from the `docs/` folder,
 47→ * builds the Astro site, and prints a final build summary.
 48→ */
 49→
 50→async function main() {
 51→  console.log();
 52→  printBanner('TEA Documentation Build Pipeline');
 53→  console.log();
 54→  console.log(`Project root: ${PROJECT_ROOT}`);
 55→  console.log(`Build directory: ${BUILD_DIR}`);
 56→  console.log();
 57→
 58→  // Check for broken internal links before building
 59→  checkDocLinks();
 60→
 61→  cleanBuildDirectory();
 62→
 63→  const docsDir = path.join(PROJECT_ROOT, 'docs');
 64→  const artifactsDir = await generateArtifacts(docsDir);
 65→  const siteDir = buildAstroSite();
 66→
 67→  printBuildSummary(docsDir, artifactsDir, siteDir);
 68→}
 69→
 70→main().catch((error) => {
 71→  console.error(error);
 72→  process.exit(1);
 73→});
 74→
 75→// =============================================================================
 76→// Pipeline Stages
 77→/**
 78→ * Generate LLM files and downloadable bundles for the documentation pipeline.
 79→ *
 80→ * Creates the build/artifacts directory, writes `llms.txt` and `llms-full.txt` (sourced from the provided docs directory),
 81→ * and produces download ZIP bundles.
 82→ *
 83→ * @param {string} docsDir - Path to the source docs directory containing Markdown files.
 84→ * @returns {string} Path to the created artifacts directory.
 85→ */
 86→
 87→async function generateArtifacts(docsDir) {
 88→  printHeader('Generating LLM files and download bundles');
 89→
 90→  const outputDir = path.join(BUILD_DIR, 'artifacts');
 91→  fs.mkdirSync(outputDir, { recursive: true });
 92→
 93→  // Generate LLM files reading from docs/, output to artifacts/
 94→  generateLlmsTxt(outputDir);
 95→  generateLlmsFullTxt(docsDir, outputDir);
 96→  await generateDownloadBundles(outputDir);
 97→
 98→  console.log();
 99→  console.log(`  \u001B[32m✓\u001B[0m Artifact generation complete`);
100→
101→  return outputDir;
102→}
103→
104→/**
105→ * Builds the Astro + Starlight site and copies generated artifacts into the site output directory.
106→ *
107→ * @returns {string} The filesystem path to the built site directory (e.g., build/site).
108→ */
109→function buildAstroSite() {
110→  printHeader('Building Astro + Starlight site');
111→
112→  const siteDir = path.join(BUILD_DIR, 'site');
113→  const artifactsDir = path.join(BUILD_DIR, 'artifacts');
114→
115→  // Build Astro site (outputs to build/site via astro.config.mjs)
116→  runAstroBuild();
117→  copyArtifactsToSite(artifactsDir, siteDir);
118→
119→  // No longer needed: Inject AI agents banner into every HTML page
120→  // injectAgentBanner(siteDir);
121→
122→  console.log();
123→  console.log(`  \u001B[32m✓\u001B[0m Astro build complete`);
124→
125→  return siteDir;
126→}
127→
128→// =============================================================================
129→// LLM File Generation
130→/**
131→ * Create a concise llms.txt summary file containing project metadata, core links, and quick navigation entries for LLM consumption.
132→ *
133→ * Writes the file to `${outputDir}/llms.txt`.
134→ *
135→ * @param {string} outputDir - Destination directory where `llms.txt` will be written.
136→ */
137→
138→function generateLlmsTxt(outputDir) {
139→  console.log('  → Generating llms.txt...');
140→
141→  const content = [
142→    '# Test Architect (TEA) Documentation',
143→    '',
144→    '> Risk-based test strategy, automation guidance, and release gate decisions for quality-driven development.',
145→    '',
146→    `Documentation: ${SITE_URL}`,
147→    `Repository: ${REPO_URL}`,
148→    `Full docs: ${SITE_URL}/llms-full.txt`,
149→    '',
150→    '## Quick Start',
151→    '',
152→    `- **[TEA Lite Quickstart](${SITE_URL}/docs/tutorials/tea-lite-quickstart)** - Get started in 30 minutes`,
153→    `- **[Installation](${SITE_URL}/)** - Installation guide`,
154→    '',
155→    '## Core Workflows',
156→    '',
157→    `- **[Test Design (TD)](${SITE_URL}/docs/how-to/workflows/run-test-design)** - Risk-based test planning`,
158→    `- **[ATDD (AT)](${SITE_URL}/docs/how-to/workflows/run-atdd)** - Failing acceptance tests first`,
159→    `- **[Automate (TA)](${SITE_URL}/docs/how-to/workflows/run-automate)** - Expand automation coverage`,
160→    `- **[Trace (TR)](${SITE_URL}/docs/how-to/workflows/run-trace)** - Requirements traceability`,
161→    '',
162→    '## Additional Workflows',
163→    '',
164→    `- **[Framework (TF)](${SITE_URL}/docs/how-to/workflows/setup-test-framework)** - Scaffold test framework`,
165→    `- **[CI (CI)](${SITE_URL}/docs/how-to/workflows/setup-ci)** - CI/CD quality pipeline`,
166→    `- **[Test Review (RV)](${SITE_URL}/docs/how-to/workflows/run-test-review)** - Quality audit`,
167→    `- **[NFR Assess (NR)](${SITE_URL}/docs/how-to/workflows/run-nfr-assess)** - Non-functional requirements`,
168→    '',
169→    '---',
170→    '',
171→    '## Quick Links',
172→    '',
173→    `- [Full Documentation (llms-full.txt)](${SITE_URL}/llms-full.txt) - Complete docs for AI context`,
174→    `- [Source Bundle](${SITE_URL}/downloads/tea-sources.zip) - Complete source code`,
175→    `- [Prompts Bundle](${SITE_URL}/downloads/tea-prompts.zip) - Agent prompts and workflows`,
176→    '',
177→  ].join('\n');
178→
179→  const outputPath = path.join(outputDir, 'llms.txt');
180→  fs.writeFileSync(outputPath, content, 'utf-8');
181→  console.log(`    Generated llms.txt (${content.length.toLocaleString()} chars)`);
182→}
183→
184→/**
185→ * Builds a consolidated llms-full.txt containing all Markdown files under docsDir wrapped in <document path="..."> tags for LLM consumption.
186→ *
187→ * Writes the generated file to outputDir/llms-full.txt. Files matching LLM_EXCLUDE_PATTERNS are skipped; read errors for individual files are logged. The combined content is validated against configured size thresholds (will exit on overflow and warn if near limit).
188→ * @param {string} docsDir - Root directory containing source Markdown files; paths in the output are relative to this directory.
189→ * @param {string} outputDir - Directory where llms-full.txt will be written.
190→ */
191→function generateLlmsFullTxt(docsDir, outputDir) {
192→  console.log('  → Generating llms-full.txt...');
193→
194→  const date = new Date().toISOString().split('T')[0];
195→  const files = getAllMarkdownFiles(docsDir);
196→
197→  const output = [
198→    '# Test Architect (TEA) Documentation (Full)',
199→    '',
200→    '> Complete documentation for AI consumption',
201→    `> Generated: ${date}`,
202→    `> Repository: ${REPO_URL}`,
203→    '',
204→  ];
205→
206→  let fileCount = 0;
207→  let skippedCount = 0;
208→
209→  for (const mdPath of files) {
210→    if (shouldExcludeFromLlm(mdPath)) {
211→      skippedCount++;
212→      continue;
213→    }
214→
215→    const fullPath = path.join(docsDir, mdPath);
216→    try {
217→      const content = readMarkdownContent(fullPath);
218→      output.push(`<document path="${mdPath}">`, content, '</document>', '');
219→      fileCount++;
220→    } catch (error) {
221→      console.error(`    Warning: Could not read ${mdPath}: ${error.message}`);
222→    }
223→  }
224→
225→  const result = output.join('\n');
226→  validateLlmSize(result);
227→
228→  const outputPath = path.join(outputDir, 'llms-full.txt');
229→  fs.writeFileSync(outputPath, result, 'utf-8');
230→
231→  const tokenEstimate = Math.floor(result.length / 4).toLocaleString();
232→  console.log(
233→    `    Processed ${fileCount} files (skipped ${skippedCount}), ${result.length.toLocaleString()} chars (~${tokenEstimate} tokens)`,
234→  );
235→}
236→
237→/**
238→ * Collects all Markdown (.md) files under a directory and returns their paths relative to a base directory.
239→ * @param {string} dir - Directory to search for Markdown files.
240→ * @param {string} [baseDir=dir] - Base directory used to compute returned relative paths.
241→ * @returns {string[]} An array of file paths (relative to `baseDir`) for every `.md` file found under `dir`.
242→ */
243→function getAllMarkdownFiles(dir, baseDir = dir) {
244→  const files = [];
245→
246→  for (const entry of fs.readdirSync(dir, { withFileTypes: true })) {
247→    const fullPath = path.join(dir, entry.name);
248→
249→    if (entry.isDirectory()) {
250→      files.push(...getAllMarkdownFiles(fullPath, baseDir));
251→    } else if (entry.name.endsWith('.md')) {
252→      // Return relative path from baseDir
253→      const relativePath = path.relative(baseDir, fullPath);
254→      files.push(relativePath);
255→    }
256→  }
257→
258→  return files;
259→}
260→
261→/**
262→ * Determine whether a file path matches any configured LLM exclusion pattern.
263→ * Also excludes any files or directories starting with underscore.
264→ * @param {string} filePath - The file path to test.
265→ * @returns {boolean} `true` if excluded, `false` otherwise.
266→ */
267→function shouldExcludeFromLlm(filePath) {
268→  // Exclude if ANY path component starts with underscore
269→  // (e.g., _STYLE_GUIDE.md, _archive/file.md, dir/_STYLE_GUIDE.md)
270→  const pathParts = filePath.split(path.sep);
271→  if (pathParts.some((part) => part.startsWith('_'))) return true;
272→
273→  // Check configured patterns
274→  return LLM_EXCLUDE_PATTERNS.some((pattern) => filePath.includes(pattern));
275→}
276→
277→function readMarkdownContent(filePath) {
278→  let content = fs.readFileSync(filePath, 'utf-8');
279→
280→  if (content.startsWith('---')) {
281→    const end = content.indexOf('---', 3);
282→    if (end !== -1) {
283→      content = content.slice(end + 3).trim();
284→    }
285→  }
286→
287→  return content;
288→}
289→
290→function validateLlmSize(content) {
291→  const charCount = content.length;
292→
293→  if (charCount > LLM_MAX_CHARS) {
294→    console.error(`    ERROR: Exceeds ${LLM_MAX_CHARS.toLocaleString()} char limit`);
295→    process.exit(1);
296→  } else if (charCount > LLM_WARN_CHARS) {
297→    console.warn(`    \u001B[33mWARNING: Approaching ${LLM_WARN_CHARS.toLocaleString()} char limit\u001B[0m`);
298→  }
299→}
300→
301→// =============================================================================
302→// Download Bundle Generation
303→// =============================================================================
304→
305→async function generateDownloadBundles(outputDir) {
306→  console.log('  → Generating download bundles...');
307→
308→  const downloadsDir = path.join(outputDir, 'downloads');
309→  fs.mkdirSync(downloadsDir, { recursive: true });
310→
311→  await generateSourcesBundle(downloadsDir);
312→  await generatePromptsBundle(downloadsDir);
313→}
314→
315→async function generateSourcesBundle(downloadsDir) {
316→  const srcDir = path.join(PROJECT_ROOT, 'src');
317→  if (!fs.existsSync(srcDir)) return;
318→
319→  const zipPath = path.join(downloadsDir, 'tea-sources.zip');
320→  await createZipArchive(srcDir, zipPath, ['__pycache__', '.pyc', '.DS_Store', 'node_modules']);
321→
322→  const size = (fs.statSync(zipPath).size / 1024 / 1024).toFixed(1);
323→  console.log(`    tea-sources.zip (${size}M)`);
324→}
325→
326→/**
327→ * Create a zip archive of the project's prompts (agents and workflows) and place it in the downloads directory.
328→ *
329→ * Creates tea-prompts.zip from src/ (agents, workflows, testarch), excluding common unwanted paths, writes it to the provided downloads directory, and logs the resulting file size. If src directory does not exist, the function returns without creating a bundle.
330→ * @param {string} downloadsDir - Destination directory where tea-prompts.zip will be written.
331→ */
332→async function generatePromptsBundle(downloadsDir) {
333→  const srcDir = path.join(PROJECT_ROOT, 'src');
334→  if (!fs.existsSync(srcDir)) return;
335→
336→  const zipPath = path.join(downloadsDir, 'tea-prompts.zip');
337→  await createZipArchive(srcDir, zipPath, ['docs', '.DS_Store', '__pycache__', 'node_modules']);
338→
339→  const size = Math.floor(fs.statSync(zipPath).size / 1024);
340→  console.log(`    tea-prompts.zip (${size}K)`);
341→}
342→
343→// =============================================================================
344→// Astro Build
345→/**
346→ * Builds the Astro site to build/site (configured in astro.config.mjs).
347→ */
348→function runAstroBuild() {
349→  console.log('  → Running astro build...');
350→  execSync('npx astro build --root website', {
351→    cwd: PROJECT_ROOT,
352→    stdio: 'inherit',
353→    env: {
354→      ...process.env,
355→    },
356→  });
357→}
358→
359→/**
360→ * Copy generated artifact files into the built site directory.
361→ *
362→ * Copies llms.txt and llms-full.txt from the artifacts directory into the site directory.
363→ * If a downloads subdirectory exists under artifacts, copies it into siteDir/downloads.
364→ *
365→ * @param {string} artifactsDir - Path to the build artifacts directory containing generated files.
366→ * @param {string} siteDir - Path to the target site directory where artifacts should be placed.
367→ */
368→function copyArtifactsToSite(artifactsDir, siteDir) {
369→  console.log('  → Copying artifacts to site...');
370→
371→  fs.copyFileSync(path.join(artifactsDir, 'llms.txt'), path.join(siteDir, 'llms.txt'));
372→  fs.copyFileSync(path.join(artifactsDir, 'llms-full.txt'), path.join(siteDir, 'llms-full.txt'));
373→
374→  const downloadsDir = path.join(artifactsDir, 'downloads');
375→  if (fs.existsSync(downloadsDir)) {
376→    copyDirectory(downloadsDir, path.join(siteDir, 'downloads'));
377→  }
378→}
379→
380→// =============================================================================
381→// Build Summary
382→/**
383→ * Prints a concise end-of-build summary and displays a sample listing of the final site directory.
384→ *
385→ * @param {string} docsDir - Path to the source documentation directory used for the build.
386→ * @param {string} artifactsDir - Path to the directory containing generated artifacts (e.g., llms.txt, downloads).
387→ * @param {string} siteDir - Path to the final built site directory whose contents will be listed.
388→ */
389→
390→function printBuildSummary(docsDir, artifactsDir, siteDir) {
391→  console.log();
392→  printBanner('Build Complete!');
393→  console.log();
394→  console.log('Build artifacts:');
395→  console.log(`  Source docs:     ${docsDir}`);
396→  console.log(`  Generated files: ${artifactsDir}`);
397→  console.log(`  Final site:      ${siteDir}`);
398→  console.log();
399→  console.log(`Deployable output: ${siteDir}/`);
400→  console.log();
401→
402→  listDirectoryContents(siteDir);
403→}
404→
405→function listDirectoryContents(dir) {
406→  const entries = fs.readdirSync(dir).slice(0, 15);
407→
408→  for (const entry of entries) {
409→    const fullPath = path.join(dir, entry);
410→    const stat = fs.statSync(fullPath);
411→
412→    if (stat.isFile()) {
413→      const sizeStr = formatFileSize(stat.size);
414→      console.log(`  ${entry.padEnd(40)} ${sizeStr.padStart(8)}`);
415→    } else {
416→      console.log(`  ${entry}/`);
417→    }
418→  }
419→}
420→
421→/**
422→ * Format a byte count into a compact human-readable string using B, K, or M units.
423→ * @param {number} bytes - The number of bytes to format.
424→ * @returns {string} The formatted size: bytes as `N B` (e.g. `512B`), kilobytes truncated to an integer with `K` (e.g. `2K`), or megabytes with one decimal and `M` (e.g. `1.2M`).
425→ */
426→function formatFileSize(bytes) {
427→  if (bytes > 1024 * 1024) {
428→    return `${(bytes / 1024 / 1024).toFixed(1)}M`;
429→  } else if (bytes > 1024) {
430→    return `${Math.floor(bytes / 1024)}K`;
431→  }
432→  return `${bytes}B`;
433→}
434→
435→// =============================================================================
436→// Post-build Injection
437→/**
438→ * Recursively collects all files with the given extension under a directory.
439→ *
440→ * @param {string} dir - Root directory to search.
441→ * @param {string} ext - File extension to match (include the leading dot, e.g. ".md").
442→ * @returns {string[]} An array of file paths for files ending with `ext` found under `dir`.
443→ */
444→
445→function getAllFilesByExtension(dir, ext) {
446→  const result = [];
447→  const entries = fs.readdirSync(dir, { withFileTypes: true });
448→
449→  for (const entry of entries) {
450→    const fullPath = path.join(dir, entry.name);
451→    if (entry.isDirectory()) {
452→      result.push(...getAllFilesByExtension(fullPath, ext));
453→    } else if (entry.name.endsWith(ext)) {
454→      result.push(fullPath);
455→    }
456→  }
457→
458→  return result;
459→}
460→
461→// =============================================================================
462→// File System Utilities
463→/**
464→ * Remove any existing build output and recreate the build directory.
465→ *
466→ * Ensures the configured BUILD_DIR is empty by deleting it if present and then creating a fresh directory.
467→ */
468→
469→function cleanBuildDirectory() {
470→  console.log('Cleaning previous build...');
471→
472→  if (fs.existsSync(BUILD_DIR)) {
473→    fs.rmSync(BUILD_DIR, { recursive: true });
474→  }
475→  fs.mkdirSync(BUILD_DIR, { recursive: true });
476→}
477→
478→/**
479→ * Recursively copies all files and subdirectories from one directory to another, creating the destination if needed.
480→ *
481→ * @param {string} src - Path to the source directory to copy from.
482→ * @param {string} dest - Path to the destination directory to copy to.
483→ * @param {string[]} [exclude=[]] - List of file or directory names (not paths) to skip while copying.
484→ * @returns {boolean} `true` if the source existed and copying proceeded, `false` if the source did not exist.
485→ */
486→function copyDirectory(src, dest, exclude = []) {
487→  if (!fs.existsSync(src)) return false;
488→  fs.mkdirSync(dest, { recursive: true });
489→
490→  for (const entry of fs.readdirSync(src, { withFileTypes: true })) {
491→    if (exclude.includes(entry.name)) continue;
492→
493→    const srcPath = path.join(src, entry.name);
494→    const destPath = path.join(dest, entry.name);
495→
496→    if (entry.isDirectory()) {
497→      copyDirectory(srcPath, destPath, exclude);
498→    } else {
499→      fs.copyFileSync(srcPath, destPath);
500→    }
501→  }
502→  return true;
503→}
504→
505→/**
506→ * Create a ZIP archive of a directory, optionally excluding entries that match given substrings.
507→ * @param {string} sourceDir - Path to the source directory to archive.
508→ * @param {string} outputPath - Path to write the resulting ZIP file.
509→ * @param {string[]} [exclude=[]] - Array of substrings; any entry whose path includes one of these substrings will be omitted.
510→ * @returns {Promise<void>} Resolves when the archive has been fully written and closed, rejects on error.
511→ */
512→function createZipArchive(sourceDir, outputPath, exclude = []) {
513→  return new Promise((resolve, reject) => {
514→    const output = fs.createWriteStream(outputPath);
515→    const archive = archiver('zip', { zlib: { level: 9 } });
516→
517→    output.on('close', resolve);
518→    archive.on('error', reject);
519→
520→    archive.pipe(output);
521→
522→    const baseName = path.basename(sourceDir);
523→    archive.directory(sourceDir, baseName, (entry) => {
524→      for (const pattern of exclude) {
525→        if (entry.name.includes(pattern)) return false;
526→      }
527→      return entry;
528→    });
529→
530→    archive.finalize();
531→  });
532→}
533→
534→// =============================================================================
535→// Console Output Formatting
536→// =============================================================================
537→
538→function printHeader(title) {
539→  console.log();
540→  console.log('┌' + '─'.repeat(62) + '┐');
541→  console.log(`│ ${title.padEnd(60)} │`);
542→  console.log('└' + '─'.repeat(62) + '┘');
543→}
544→
545→/**
546→ * Prints a centered decorative ASCII banner to the console using the provided title.
547→ * @param {string} title - Text to display centered inside the banner. */
548→function printBanner(title) {
549→  console.log('╔' + '═'.repeat(62) + '╗');
550→  console.log(`║${title.padStart(31 + title.length / 2).padEnd(62)}║`);
551→  console.log('╚' + '═'.repeat(62) + '╝');
552→}
553→
554→// =============================================================================
555→// Link Checking
556→/**
557→ * Verify internal documentation links by running the link-checking script.
558→ *
559→ * Executes the Node script tools/check-doc-links.js from the project root and
560→ * exits the process with code 1 if the check fails.
561→ */
562→
563→function checkDocLinks() {
564→  printHeader('Checking documentation links');
565→
566→  try {
567→    execSync('node tools/validate-doc-links.js', {
568→      cwd: PROJECT_ROOT,
569→      stdio: 'inherit',
570→    });
571→  } catch {
572→    console.error('\n  \u001B[31m✗\u001B[0m Link check failed - fix broken links before building\n');
573→    process.exit(1);
574→  }
575→}
