331→        manualCheck++;
332→        console.log(`  [MANUAL] ${issue.href}`);
333→        console.log(`     File not found anywhere - may need to remove link`);
334→      }
335→
336→      allIssues.push({ file: relativePath, ...issue });
337→    }
338→
339→    // Apply fixes if not dry run
340→    if (!DRY_RUN) {
341→      const fixableIssues = issues.filter((i) => i.status === 'auto-fixable');
342→      if (fixableIssues.length > 0) {
343→        const updated = applyFixes(content, fixableIssues);
344→        fs.writeFileSync(filePath, updated, 'utf-8');
345→      }
346→    }
347→  }
348→}
349→
350→console.log(`\n${'─'.repeat(60)}`);
351→console.log(`\nSummary:`);
352→console.log(`   Files scanned: ${files.length}`);
353→console.log(`   Files with issues: ${filesWithIssues}`);
354→console.log(`   Total issues: ${totalIssues}`);
355→
356→if (totalIssues > 0) {
357→  console.log(`\n   Breakdown:`);
358→  console.log(`     Auto-fixable:  ${autoFixable}`);
359→  console.log(`     Needs review:  ${needsReview}`);
360→  console.log(`     Manual check:  ${manualCheck}`);
361→}
362→
363→if (totalIssues === 0) {
364→  console.log(`\n   All links valid!`);
365→} else if (DRY_RUN && autoFixable > 0) {
366→  console.log(`\nRun with --write to auto-fix ${autoFixable} issue(s)`);
367→}
